function setInitialButtonState(heroClass, playButtonClass) {
	var slick = $(heroClass).slick('getSlick');
	if (slick.options.autoplay) {
	  $(playButtonClass).removeClass('start-sliding').addClass('stop-sliding');
	} else {
	  $(playButtonClass).removeClass('stop-sliding').addClass('start-sliding');
	}
  }

  function addPlayPauseListener(heroClass, playButtonClass) {
	$(playButtonClass).click(function () {
	  var slick = $(heroClass).slick('getSlick');
	  if (slick.paused) {
		slick.slickPlay();
		$(this).removeClass('start-sliding').addClass('stop-sliding');
	  } else {
		slick.slickPause();
		$(this).removeClass('stop-sliding').addClass('start-sliding');
	  }
	});
  }

  // Set initial button state and add play/pause listener for the full-width hero
  setInitialButtonState('.hero-full-width', '.hero-play-full-width');
  addPlayPauseListener('.hero-full-width', '.hero-play-full-width');

