document.addEventListener("DOMContentLoaded", () => {
	// Embla custom js
	const initializeEmblahero = (emblaNode, options, autoplayOptions, playBtnClass) => {
		const viewportNode = emblaNode.querySelector(".hero-viewport");
		const prevBtn = emblaNode.querySelector(".hero-prev");
		const nextBtn = emblaNode.querySelector(".hero-next");
		const playBtn = emblaNode.querySelector(playBtnClass);
		const dotsNode = emblaNode.querySelector(".hero-embla .hero-dots");

		const emblaApi = EmblaCarousel(viewportNode, options, [EmblaCarouselAutoplay(autoplayOptions)]);

		const removePrevNextBtnsClickHandlers = addPrevNextBtnsClickHandlers(emblaApi, prevBtn, nextBtn);

		const removePlayBtnListeners = playBtn ? addPlayBtnListeners(emblaApi, playBtn) : null;
		const removeNavBtnListeners = addNavBtnListeners(emblaApi, prevBtn, nextBtn);
		const removeDotBtnsAndClickHandlers = addDotBtnsAndClickHandlers(emblaApi, dotsNode);

		emblaApi.on("destroy", removePrevNextBtnsClickHandlers).on("destroy", removePlayBtnListeners).on("destroy", removeNavBtnListeners).on("destroy", removeDotBtnsAndClickHandlers);
	};

	const addTogglePrevNextBtnsActive = (emblaApi, prevBtn, nextBtn) => {
		const togglePrevNextBtnsState = () => {
			if (emblaApi.canScrollPrev()) prevBtn.removeAttribute("disabled");
			else prevBtn.setAttribute("disabled", "disabled");

			if (emblaApi.canScrollNext()) nextBtn.removeAttribute("disabled");
			else nextBtn.setAttribute("disabled", "disabled");
		};

		emblaApi.on("select", togglePrevNextBtnsState).on("init", togglePrevNextBtnsState).on("reInit", togglePrevNextBtnsState);

		return () => {
			prevBtn.removeAttribute("disabled");
			nextBtn.removeAttribute("disabled");
		};
	};

	const addPrevNextBtnsClickHandlers = (emblaApi, prevBtn, nextBtn) => {
		const scrollPrev = () => {
			emblaApi.scrollPrev();
		};
		const scrollNext = () => {
			emblaApi.scrollNext();
		};
		prevBtn.addEventListener("click", scrollPrev, false);
		nextBtn.addEventListener("click", scrollNext, false);

		const removeTogglePrevNextBtnsActive = addTogglePrevNextBtnsActive(emblaApi, prevBtn, nextBtn);

		return () => {
			removeTogglePrevNextBtnsActive();
			prevBtn.removeEventListener("click", scrollPrev, false);
			nextBtn.removeEventListener("click", scrollNext, false);
		};
	};

	const addPlayBtnListeners = (emblaApi, playBtn) => {
		const togglePlayBtnState = () => {
			const autoplay = emblaApi?.plugins()?.autoplay;
			if (!autoplay) return;

			if (autoplay.isPlaying()) {
				playBtn.classList.remove("stop-sliding");
				playBtn.classList.add("start-sliding");
			} else {
				playBtn.classList.remove("start-sliding");
				playBtn.classList.add("stop-sliding");
			}
		};

		const onPlayBtnClick = () => {
			const autoplay = emblaApi?.plugins()?.autoplay;
			if (!autoplay) return;

			const playOrStop = autoplay.isPlaying() ? autoplay.stop : autoplay.play;
			playOrStop();
		};

		playBtn.addEventListener("click", onPlayBtnClick);
		emblaApi
			.on("autoplay:play", togglePlayBtnState)
			.on("autoplay:stop", togglePlayBtnState)
			.on("reInit", () => {
				togglePlayBtnState(); // Ensure initial state is set on reInit
			});

		// Set initial state based on playOnInit setting
		if (emblaApi?.plugins()?.autoplay?.options.playOnInit) {
			playBtn.classList.remove("start-sliding");
			playBtn.classList.add("stop-sliding");
		} else {
			playBtn.classList.remove("stop-sliding");
			playBtn.classList.add("start-sliding");
		}

		return () => {
			playBtn.removeEventListener("click", onPlayBtnClick);
			emblaApi.off("autoplay:play", togglePlayBtnState).off("autoplay:stop", togglePlayBtnState).off("reInit", togglePlayBtnState);
		};
	};

	const addNavBtnListeners = (emblaApi, ...navButtons) => {
		const onNavClick = () => {
			const autoplay = emblaApi?.plugins()?.autoplay;
			if (!autoplay) return;

			const resetOrStop = autoplay.options.stopOnInteraction === false ? autoplay.reset : autoplay.stop;

			resetOrStop();
		};

		navButtons.forEach((navButton) => navButton.addEventListener("click", onNavClick, true));

		return () => {
			navButtons.forEach((navButton) => navButton.removeEventListener("click", onNavClick, true));
		};
	};

	const addDotBtnsAndClickHandlers = (emblaApi, dotsNode) => {
		let dotNodes = [];

		const addDotBtnsWithClickHandlers = () => {
			dotsNode.innerHTML = emblaApi
				.scrollSnapList()
				.map(() => '<button class="hero-dot" type="button"></button>')
				.join("");

			const scrollTo = (index) => {
				emblaApi.scrollTo(index);
			};

			dotNodes = Array.from(dotsNode.querySelectorAll(".hero-dot"));
			dotNodes.forEach((dotNode, index) => {
				dotNode.addEventListener("click", () => scrollTo(index), false);
			});
		};

		const toggleDotBtnsActive = () => {
			const previous = emblaApi.previousScrollSnap();
			const selected = emblaApi.selectedScrollSnap();
			dotNodes[previous].classList.remove("hero-dot-selected");
			dotNodes[selected].classList.add("hero-dot-selected");
		};

		emblaApi.on("init", addDotBtnsWithClickHandlers).on("reInit", addDotBtnsWithClickHandlers).on("init", toggleDotBtnsActive).on("reInit", toggleDotBtnsActive).on("select", toggleDotBtnsActive);

		return () => {
			dotsNode.innerHTML = "";
		};
	};

	// Initialize full width slider
	const fullWidthNode = document.querySelector(".hero-embla-full-width .hero-full-width");
	if (fullWidthNode) {
		initializeEmblahero(fullWidthNode, { loop: true }, { playOnInit: false, delay: 3000 }, ".hero-embla-play-full-width");
	}
});

